import{_ as n,c as o,o as a,ag as i}from"./chunks/framework.piE7uVCg.js";const p=JSON.parse('{"title":"Zones","description":"","frontmatter":{},"headers":[],"relativePath":"securite/incendie/normes/zones.md","filePath":"securite/incendie/normes/zones.md"}'),s={name:"securite/incendie/normes/zones.md"};function r(t,e,d,u,l,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="zones" tabindex="-1"><a href="./readme.html">Zones</a> <a class="header-anchor" href="#zones" aria-label="Permalink to &quot;[Zones](readme.md)&quot;">​</a></h1><h2 id="zone-de-detection-zd" tabindex="-1">Zone de détection ZD <a class="header-anchor" href="#zone-de-detection-zd" aria-label="Permalink to &quot;Zone de détection ZD&quot;">​</a></h2><p>La zone de détection désigne « soit une zone surveillée par un ensemble de détecteurs incendie (DI), soit une zone surveillée par un ensemble de déclencheurs manuels, auxquels correspond, dans chaque cas, une signalisation commune.»</p><h2 id="zone-de-securite-zs" tabindex="-1">Zone de sécurité ZS <a class="header-anchor" href="#zone-de-securite-zs" aria-label="Permalink to &quot;Zone de sécurité ZS&quot;">​</a></h2><p>C’est une zone « susceptible d’être mise en sécurité par le système de mise en sécurité incendie (SMSI). » Selon la fonction de mise en sécurité réalisée dans la ZS.</p><p>On distingue :</p><ol><li>La ZC, zone géographique où la fonction compartimentage est réalisée ;</li><li>La ZF, zone géographique dans laquelle la fonction désenfumage est réalisée.</li></ol><h2 id="zone-d-alarme-za" tabindex="-1">Zone d&#39;alarme ZA <a class="header-anchor" href="#zone-d-alarme-za" aria-label="Permalink to &quot;Zone d&#39;alarme ZA&quot;">​</a></h2><p>La zone de diffusion d’alarme est une « zone géographique dans laquelle le signal d’alarme générale est audible pour donner l’ordre d’évacuation. Une zone de diffusion d’alarme peut comporter un ou plusieurs diffuseurs sonores (DS). Elle constitue une zone de mise en sécurité (ZS). Lorsqu’il est prévu un déverrouillage automatique des issues de secours, celle-ci doit s’effectuer par ZA dans le cadre de la fonction d’évacuation du SMSI. »</p><p>Il est important de retenir le principe de l’emboîtement des zones tel que défini par la norme NF S 61-932 qui prévoit qu’une zone de diffusion d’alarme (ZA) doit englober une ou plusieurs zones de mise en sécurité (ZS). Chaque zone de mise en sécurité devant englober une ou plusieurs zones de détection (ZD).</p><p>En tenant compte de ces distinctions le principe d’emboîtement se traduit par:</p><ul><li>une zone de diffusion d’alarme (ZA) doit englober une ou plusieurs zones de compartimentage (ZC). Chaque zone de compartimentage doit englober une ou plusieurs zones de désenfumage (ZF). Et chaque zone de désenfumage doit englober une ou plusieurs zones de détection automatique (ZDA) ;</li><li>une zone de diffusion d’alarme (ZA) doit englober une ou plusieurs zones de détection manuelle (ZDM).</li></ul><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://cr1.fr/ssi-principes-systemes-securite-incendie/" target="_blank" rel="noreferrer">Source</a></li></ul>',14)])])}const z=n(s,[["render",r]]);export{p as __pageData,z as default};
